body:
rom.v:
```verilog
module top(input clk, input [3:0] addr, output reg [15:0] q);
	reg [15:0] rom[0:15];
	initial begin : rom_init
		integer i;
		for (i = 0; i < 16; i = i + 1'b1)
			rom[i] = i[0] ? 16'hAAAA : 16'h5555;
	end

	always @(posedge clk)
		q <= rom[addr];
endmodule
```

rom_test.cc:
```c++
#include "rom.cc"
#include <iostream>

int main() {
  cxxrtl_design::p_top top;
  
  for (int i = 0; i < 16; i++) {
    top.p_addr.next = value<4> {i};
    top.p_clk.next = value<1> {1u};
    top.step();
    top.p_clk.next = value<1> {0u};
    top.step();
    std::cerr << top.p_q.curr << std::endl;
  }
}
```

Command line:
```
yosys -p "prep -top top; write_cxxrtl rom.cc" rom.v && g++ -I`yosys-config --datdir`/include -o rom_test rom_test.cc && ./rom_test
```

Output from `rom_test` is all 16'h0000 rather than 16'h5555/16'hAAAA alternating as expected. Looking inside the generated code, the `if (value<1>{0u})` doesn't look right here:
```c++
	auto tmp_0 = memory_index(p_addr.curr, 0, 16);
	if (value<1>{0u}) {
		assert(tmp_0.valid && "out of bounds read");
		if(tmp_0.valid) {
			i_0_5c_q_5b_15_3a_0_5d_ = memory_p_rom[tmp_0.index];
		} else {
			i_0_5c_q_5b_15_3a_0_5d_ = value<16> {};
		}
	}
```

